<script setup lang="ts">import{computed}from'vue';import{useRoute}from'vue-router';import{X}from'lucide-vue-next';import{useCourseStore}from'@/stores/courses';import LessonPlayer from '@/components/lesson/LessonPlayer.vue';const route=useRoute(),store=useCourseStore();const found=computed(()=>store.findLesson(String(route.params.lessonId)))</script><template><div class="preview-shell"><header><div><b>Предпросмотр урока</b><small>Так его увидит ученик</small></div><RouterLink v-if="found" :to="`/app/lessons/${found.lesson.id}/editor`" class="icon-button"><X/></RouterLink></header><LessonPlayer v-if="found" :lesson="found.lesson"/><section v-else class="empty-state"><h2>Урок не найден</h2></section></div></template>